  // do not cache when testing to avoid flakyness
  if (!isMockedEnvironment && apiCache.has(url)) {
    return apiCache.get(url)
  }

  const response = await axios.get<T>(url)

  if (!isMockedEnvironment) {
    apiCache.set(url, response)
  }

  return response
}

